sql:
SELECT patient_id, result
FROM test_results
WHERE test_performed_by = 'drjones';

SELECT test_type_name 
FROM test_types 
WHERE test_type_id = 1;

external_knowledge:
- 'edit_patients' permission refers to the ability to modify patient records;
- UCAYALI department is a specific area within the healthcare facility;
- The rank of tests is determined based on the sequence they were performed by each health professional.

sql:
SELECT COUNT(*) 
FROM test_results 
WHERE test_location = 'DepartmentName';

SELECT patient_id, test_type_id
FROM test_results
WHERE tipo_prueba = 'PCR' AND result = 'positive';

SELECT permission_name, permission_description
FROM permissions
WHERE permission_id > 1;

SELECT tipo_prueba AS test_conducted, result AS test_result, fecha_prueba AS test_date
FROM test_results
WHERE test_performed_by = 'Mary';

SELECT DISTINCT u.*
FROM users u
INNER JOIN test_results tr ON u.username = tr.test_performed_by;
